#!/usr/bin/env python3
"""Supply Chain Quality Analysis"""

import pandas as pd
import numpy as np
import json, re
from collections import deque
from pathlib import Path

BASE = Path('/app')

# ===== PHASE 1: LOAD AND AGGREGATE SALES DATA =====
print("Loading sales data...")
sales_raw = pd.read_csv(BASE / 'sales_log.csv')
print(f"Raw rows: {len(sales_raw)}")

# Aggregate to (Day, Store_ID, Product_ID) level (multiple consumer rows per day)
sales = sales_raw.groupby(['Day', 'Store_ID', 'Product_ID']).agg(
    Reported_Demand=('Reported_Demand', 'sum'),
    Sold_Quantity=('Sold_Quantity', 'sum'),
    Lost_Sales=('Lost_Sales', 'sum')
).reset_index()

print(f"Aggregated rows: {len(sales)}")
products = sorted(sales['Product_ID'].unique())
stores = sorted(sales['Store_ID'].unique())
all_days = sorted(sales['Day'].unique())
print(f"Products: {len(products)}, Stores: {len(stores)}, Days: {len(all_days)}")

# ===== PHASE 2: PARSE RAW FILES =====
print("\nParsing wholesaler sequence numbers...")
wh_seq = {}  # {day: {supplier: seq}}
for f in (BASE / 'raw_wholesaler_receipts').iterdir():
    txt = f.read_text()
    d = re.search(r'DAY:\s*(\d+)', txt)
    s = re.search(r'SUPPLIER_ID:\s*(PR_\d+)', txt)
    q = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', txt)
    if d and s and q:
        wh_seq.setdefault(int(d.group(1)), {})[s.group(1)] = int(q.group(1))
print(f"Wholesaler seq: {len(wh_seq)} days")

print("Parsing supplier deliveries...")
sup_del = {}  # {day: {supplier: {product: qty}}}
for f in (BASE / 'raw_supplier_receipts').iterdir():
    m = re.match(r'day_(\d+)_(PR_\d+)_(.*)', f.stem)
    if not m:
        continue
    day, sup, fmt = int(m.group(1)), m.group(2), m.group(3)
    txt = f.read_text().strip()
    items = {}
    if 'text-template' in fmt:
        for m2 in re.finditer(r'delivered (\d+) units of product (P_\d+)', txt):
            items[m2.group(2)] = items.get(m2.group(2), 0) + int(m2.group(1))
    elif 'key-value' in fmt:
        for m2 in re.finditer(r'PRODUCT:\s*(P_\d+)\s*\|\s*DELIVERED_QTY:\s*(\d+)', txt):
            items[m2.group(1)] = items.get(m2.group(1), 0) + int(m2.group(2))
    elif 'table-csv' in fmt:
        for line in txt.split('\n')[1:]:
            p = [x.strip() for x in line.split(';')]
            if len(p) >= 2 and p[0].startswith('P_'):
                try: items[p[0]] = items.get(p[0], 0) + int(p[1])
                except: pass
    elif 'api-json' in fmt:
        try:
            data = json.loads(txt)
            for item in data.get('items', []):
                prod = item.get('prod_id', '')
                qty = item.get('delivered_qty', 0)
                if prod: items[prod] = items.get(prod, 0) + int(qty)
        except: pass
    if items:
        sup_del.setdefault(day, {})[sup] = items
print(f"Supplier deliveries: {len(sup_del)} days")

print("Parsing store orders...")
st_orders = {}  # {day: {store: {product: qty}}}
for f in (BASE / 'raw_orders').iterdir():
    m = re.match(r'day_(\d+)_(S_\d+)_(.*)', f.stem)
    if not m:
        continue
    day, store, fmt = int(m.group(1)), m.group(2), m.group(3)
    txt = f.read_text().strip()
    items = {}
    if 'text-template' in fmt:
        for m2 in re.finditer(r'deliver (\d+) units of product (P_\d+)', txt):
            items[m2.group(2)] = int(m2.group(1))
    elif 'key-value' in fmt:
        for m2 in re.finditer(r'ORDER_PRODUCT:\s*(P_\d+)\s*\|\s*ORDER_QTY:\s*(\d+)', txt):
            items[m2.group(1)] = int(m2.group(2))
    elif 'table-csv' in fmt:
        for line in txt.split('\n')[1:]:
            p = [x.strip() for x in line.split(';')]
            if len(p) >= 2 and p[0].startswith('P_'):
                try: items[p[0]] = int(p[1])
                except: pass
    elif 'api-json' in fmt:
        try:
            data = json.loads(txt)
            for item in data.get('items', []):
                prod = item.get('prod_id', item.get('product_id', ''))
                qty = item.get('qty', item.get('quantity', 0))
                if prod: items[prod] = int(qty)
        except: pass
    if items:
        st_orders.setdefault(day, {})[store] = items
print(f"Store orders: {len(st_orders)} days")

print("Parsing wholesaler store receipts...")
st_seq = {}  # {day: {store: (seq, total)}}
for f in (BASE / 'raw_wholesaler_store_receipts').iterdir():
    txt = f.read_text()
    d = re.search(r'DAY:\s*(\d+)', txt)
    s = re.search(r'STORE_ID:\s*(S_\d+)', txt)
    q = re.search(r'DAILY_SEQUENCE_NO:\s*(\d+)', txt)
    t = re.search(r'TOTAL_DELIVERED_UNITS:\s*(\d+)', txt)
    if d and s and q and t:
        st_seq.setdefault(int(d.group(1)), {})[s.group(1)] = (int(q.group(1)), int(t.group(1)))
print(f"Store seq: {len(st_seq)} days")

# ===== PHASE 3: FIFO SIMULATION =====
print("\nRunning FIFO simulation...")
products_set = set(products)
store_inv = {s: {p: deque() for p in products} for s in stores}
# batch_supplier[day][store][product] = supplier at front of queue when sales happen
batch_supplier = {}

for day in all_days:
    batch_supplier[day] = {s: {} for s in stores}

    # Build wholesaler inventory (sorted by supplier sequence = FIFO from suppliers)
    day_sups = sorted(wh_seq.get(day, {}).items(), key=lambda x: x[1])
    wh_inv = {p: deque() for p in products}
    for sup, seq in day_sups:
        for prod, qty in sup_del.get(day, {}).get(sup, {}).items():
            if qty > 0 and prod in products_set:
                wh_inv[prod].append([qty, sup])

    # Allocate to stores (sorted by store sequence = brutal first-come)
    for store, (seq, total) in sorted(st_seq.get(day, {}).items(), key=lambda x: x[1][0]):
        for prod, ordered_qty in st_orders.get(day, {}).get(store, {}).items():
            if prod not in products_set:
                continue
            remaining = ordered_qty
            while remaining > 0 and wh_inv.get(prod):
                batch = wh_inv[prod][0]
                take = min(remaining, batch[0])
                # Append to store's FIFO queue (merge if same supplier+day)
                if (store_inv[store][prod] and
                        store_inv[store][prod][-1][1] == batch[1] and
                        store_inv[store][prod][-1][2] == day):
                    store_inv[store][prod][-1][0] += take
                else:
                    store_inv[store][prod].append([take, batch[1], day])
                batch[0] -= take
                remaining -= take
                if batch[0] == 0:
                    wh_inv[prod].popleft()

    # Process sales: record front-of-queue supplier BEFORE consuming
    day_sales = sales[sales['Day'] == day]
    for _, row in day_sales.iterrows():
        s, p = row['Store_ID'], row['Product_ID']
        sold = int(row['Sold_Quantity'])
        if store_inv[s][p]:
            batch_supplier[day][s][p] = store_inv[s][p][0][1]
        remaining = sold
        while remaining > 0 and store_inv[s][p]:
            batch = store_inv[s][p][0]
            take = min(remaining, batch[0])
            batch[0] -= take
            remaining -= take
            if batch[0] == 0:
                store_inv[s][p].popleft()

print("FIFO simulation complete!")

# ===== PHASE 4: DETECT QUALITY REJECTIONS =====
print("\nDetecting quality rejections...")

confirmed = {p: set() for p in products}
rejections_found = []

# Recovery fractions by day-offset (0-indexed)
RECOVERY = [0.2]*3 + [0.5]*4 + [0.8]*7  # 14 days

for prod in products:
    prod_df = sales[sales['Product_ID'] == prod]
    # Cross-store median demand per day captures calendar effects
    cross_med = prod_df.groupby(['Day', 'Store_ID'])['Reported_Demand'].sum().groupby('Day').median()

    for store in stores:
        store_s = prod_df[prod_df['Store_ID'] == store].groupby('Day')['Reported_Demand'].sum()
        if store_s.empty or cross_med.empty or cross_med.mean() == 0:
            continue

        # Store-specific scale (accounts for store size differences)
        scale = store_s.mean() / cross_med.mean()
        if scale <= 0:
            continue

        # Normalized ratio: actual / (scale * calendar_baseline)
        common = store_s.index.intersection(cross_med.index)
        ratio = pd.Series({d: store_s[d] / (cross_med[d] * scale) for d in common if cross_med[d] * scale > 0})

        # Upper quartile represents "normal" ratio (avoids dip days pulling mean down)
        q75 = ratio.quantile(0.75) if len(ratio) > 20 else ratio.median()
        if q75 <= 0:
            continue
        norm = ratio / q75

        # Scan for rejection start days: ratio drops below 0.80
        for day in sorted(norm.index):
            cur = norm.get(day, 1.0)
            if cur >= 0.80:
                continue
            # Must be a NEW drop (previous day was normal)
            prev = norm.get(day - 1, 1.0)
            if prev < 0.80:
                continue

            # Check 14-day recovery pattern is present
            pddays = [d for d in range(day, day + 14) if d in norm.index]
            if len(pddays) < 10:
                continue

            vals = [norm[d] for d in pddays]

            # Three recovery phases must increase monotonically
            p1 = np.mean(vals[:3]) if len(vals) >= 3 else None
            p2 = np.mean(vals[3:7]) if len(vals) >= 7 else None
            p3 = np.mean(vals[7:14]) if len(vals) >= 14 else None
            phases = [x for x in [p1, p2, p3] if x is not None]
            if len(phases) < 2:
                continue
            if not all(phases[i] < phases[i+1] for i in range(len(phases)-1)):
                continue

            # Demand must recover to near-normal after 14 days
            after = [norm.get(day + k) for k in range(14, 18) if (day + k) in norm.index]
            if after and np.mean(after) < 0.85:
                continue

            # The bad batch was consumed the day BEFORE recovery starts
            # (consumers bought from bad batch on day-1, enter recovery starting today)
            sup = batch_supplier.get(day - 1, {}).get(store, {}).get(prod)
            if sup is None:
                sup = batch_supplier.get(day, {}).get(store, {}).get(prod)

            if sup:
                confirmed[prod].add(sup)
                rejections_found.append({
                    'product': prod, 'store': store, 'day': day,
                    'supplier': sup, 'ratio': round(cur, 3),
                    'phases': [round(x, 3) for x in phases]
                })
                print(f"  REJECT: {prod} @ {store}, day={day}, norm={cur:.3f}, "
                      f"phases={[round(x,2) for x in phases]}, supplier={sup}")

print(f"\nTotal rejection events: {len(rejections_found)}")

# ===== PHASE 5: OUTPUT RESULTS =====
result = {p: sorted(list(v)) for p, v in confirmed.items()}

print("\n=== CONFIRMED QUALITY OFFENDERS ===")
for p, sups in sorted(result.items()):
    print(f"  {p}: {sups}")

with open('/app/answer.json', 'w') as f:
    json.dump(result, f, indent=2)

print("\nAnswer written to /app/answer.json")

